let a = 15;
if (a >= 10) {
  console.log('aは10以上です'); // aは10以上ですが出力される
}

let a = 5;
if (a >= 10) {
  console.log('aは10以上です');
} else {
  console.log('aは10未満です'); // aは10未満ですが出力される
}

let a = 25;
if (a >= 10 && a < 20) {
  console.log('aは10以上20未満です');
} else if (a >= 20) {
  console.log('aは20以上です'); // aは20以上ですが出力される
} else {
  console.log('aは10未満です');
}

let day = 'Tuesday';
switch(day) {
  case 'Monday':
    console.log('今日は月曜日です');
    break;
  case 'Tuesday':
    console.log('今日は火曜日です'); // 今日は火曜日ですが出力される
    break;
  // 以下、WednesdayからSundayまでのcaseを追加...
  default:
    console.log('無効な曜日です');
    break;
}

let a = 15;
let b = 18;
if (a >= 10 && b < 20) {
  console.log('aは10以上で、bは20未満です'); // aは10以上で、bは20未満ですが出力される
}

let a = 9;
let b = 20;
if (a >= 10 || b >= 20) {
  console.log('aは10以上、またはbは20以上です'); // aは10以上、またはbは20以上ですが出力される
}

let a = 5;
if (!(a >= 10)) {
  console.log('aは10未満です'); // aは10未満ですが出力される
}

let a = 15;
if (a < 10) {
  console.log('aは10未満です');
} else if (a < 20) {
  console.log('aは10以上20未満です'); // aは10以上20未満ですが出力される
} else {
  console.log('aは20以上です');
}

let a = 'Hello';
if (a === 'Hello') {
  console.log('Hello World!'); // Hello World!が出力される
} else {
  console.log('Goodbye World!');
}

let a = [1, 2, 3, 4, 5];
if (a.length >= 5) {
  console.log('aの長さは5以上です'); // aの長さは5以上ですが出力される
}

let num = 15;
if (num >= 10) {
  console.log('numは10以上です'); // numは10以上ですが出力される
} else {
  console.log('numは10未満です');
}

let a = 15;
if (a >= 10 && a <= 20) {
  console.log('aは10以上20以下です'); // aは10以上20以下ですが出力される
}

let a = 10;
let b = 20;
if (a >= 10 && b >= 10) {
  console.log('aとbは共に10以上です'); // aとbは共に10以上ですが出力される
} else {
  console.log('aまたはbが10未満です');
}

let a = 2;
switch (a) {
  case 1:
    console.log('aは1です');
    break;
  case 2:
    console.log('aは2です'); // aは2ですが出力される
    break;
  default:
    console.log('aは1でも2でもありません');
    break;
}

let str = 'Hello';
if (str === 'Hello') {
  console.log('Hello World!'); // Hello World!が出力される
} else {
  console.log('Goodbye World!');
}

let bool = true;
if (bool) {
  console.log('boolはtrueです'); // boolはtrueですが出力される
} else {
  console.log('boolはfalseです');
}
